import pytest
from source import wrap

@pytest.mark.parametrize("text, cols, expected", [
    ("aaa bbb ccc", 4, ['aaa', 'bbb', 'ccc'])
])
def test_wrap_trailing_words_not_appended(text, cols, expected):
    result = wrap(text, cols)
    assert result == expected, f"Expected {expected}, but got {result}"
